function trailingZeros(n) {
  // Each trailing zero comes from a factor of 10 = 2 × 5 in n!.
  // Factors of 2 are plentiful — the bottleneck is factors of 5.
  // Count: how many multiples of 5 are in 1..n?  Plus multiples of 25,
  // plus multiples of 125, etc.
}

solution:
// O(log n) — we divide n by 5 each iteration.
//   n=100: 100/5=20, 20/5=4, 4/5=0 → 20 + 4 = 24 trailing zeros
// We never compute the factorial itself.
function trailingZeros(n) {
  let count = 0;
  while (n > 0) {
    n = Math.floor(n / 5);
    count += n;
  }
  return count;
}
